// GET /api/accounts/active returns a bare JSON array. Depending on n8n version
// that either lands as one item whose .json IS the array, or is already split
// into one item per account. Handle both so this is reliable either way.
const first = $input.all()[0];
const raw = Array.isArray(first.json) ? first.json : $input.all().map(i => i.json);
return raw.map(account => ({ json: account }));

const raw = $json.data || [];
const account = $('Get Active Accounts').item.json;

function extractConversions(r) {
  const purchases = (r.actions || []).filter(a => a.action_type === 'purchase');
  const purchaseValues = (r.action_values || []).filter(a => a.action_type === 'purchase');
  const conversions = purchases.reduce((sum, a) => sum + (parseInt(a.value, 10) || 0), 0);
  const revenue = purchaseValues.reduce((sum, a) => sum + (parseFloat(a.value) || 0), 0);
  return { conversions, revenue };
}

const campaigns = raw.map(r => {
  const { conversions, revenue } = extractConversions(r);
  return {
    campaign_id: String(r.campaign_id || ''),
    campaign_name: String(r.campaign_name || ''),
    impressions: parseInt(r.impressions, 10) || 0,
    clicks: parseInt(r.clicks, 10) || 0,
    spend: parseFloat(r.spend) || 0,
    conversions,
    revenue,
  };
});

return {
  json: {
    account_id: account.account_id,
    account_name: account.name,
    meta_ads_cred: account.meta_ads,
    google_ads_cred: account.google_ads,
    campaigns,
  },
};

const raw = $json.data || [];
const prev = $('Normalize Meta Campaigns').item.json;

function extractConversions(r) {
  const purchases = (r.actions || []).filter(a => a.action_type === 'purchase');
  const purchaseValues = (r.action_values || []).filter(a => a.action_type === 'purchase');
  const conversions = purchases.reduce((sum, a) => sum + (parseInt(a.value, 10) || 0), 0);
  const revenue = purchaseValues.reduce((sum, a) => sum + (parseFloat(a.value) || 0), 0);
  return { conversions, revenue };
}

const ads = raw.map(r => {
  const { conversions, revenue } = extractConversions(r);
  return {
    ad_id: String(r.ad_id || ''),
    ad_name: String(r.ad_name || ''),
    campaign_id: String(r.campaign_id || ''),
    campaign_name: String(r.campaign_name || ''),
    impressions: parseInt(r.impressions, 10) || 0,
    clicks: parseInt(r.clicks, 10) || 0,
    spend: parseFloat(r.spend) || 0,
    conversions,
    revenue,
  };
});

const ad_ids_csv = ads.map(a => a.ad_id).filter(Boolean).join(',');

return { json: { ...prev, ads, ad_ids_csv } };

const state = $json;
let creatives = {};

if (state.ad_ids_csv) {
  // Note: depending on n8n version this may need to be $helpers.httpRequest
  // instead of this.helpers.httpRequest — try the other one if this throws.
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://graph.facebook.com/v19.0/',
    qs: {
      ids: state.ad_ids_csv,
      fields: 'creative{title,body,thumbnail_url,object_type}',
      access_token: state.meta_ads_cred.access_token,
    },
    json: true,
  });
  for (const [adId, obj] of Object.entries(resp || {})) {
    const c = (obj && obj.creative) || {};
    creatives[adId] = {
      title: c.title || c.body || '',
      thumbnail_url: c.thumbnail_url || '',
      object_type: (c.object_type || 'image').toLowerCase(),
    };
  }
}

return { json: { ...state, creatives } };

const prev = $('Merge Breakdown Country').item.json;
const regionRows = $json.data || [];

function extractConversions(r) {
  const purchases = (r.actions || []).filter(a => a.action_type === 'purchase');
  const purchaseValues = (r.action_values || []).filter(a => a.action_type === 'purchase');
  const conversions = purchases.reduce((sum, a) => sum + (parseInt(a.value, 10) || 0), 0);
  const revenue = purchaseValues.reduce((sum, a) => sum + (parseFloat(a.value) || 0), 0);
  return { conversions, revenue };
}

function normalizeRows(rows, breakdownType, field) {
  return rows.map(r => {
    const { conversions, revenue } = extractConversions(r);
    return {
      breakdown_type: breakdownType,
      breakdown_value: String(r[field] || 'unknown'),
      campaign_id: String(r.campaign_id || ''),
      impressions: parseInt(r.impressions, 10) || 0,
      clicks: parseInt(r.clicks, 10) || 0,
      spend: parseFloat(r.spend) || 0,
      reach: parseInt(r.reach, 10) || 0,
      conversions,
      revenue,
    };
  });
}

const breakdowns = [
  ...normalizeRows(prev.breakdown_age || [], 'age', 'age'),
  ...normalizeRows(prev.breakdown_device || [], 'device_platform', 'device_platform'),
  ...normalizeRows(prev.breakdown_country || [], 'country', 'country'),
  ...normalizeRows(regionRows, 'region', 'region'),
];

return { json: { ...prev, breakdowns } };

const prev = $('Merge Breakdown Region').item.json;
const adsets = $json.data || [];

const targeting = [];
for (const adset of adsets) {
  const t = adset.targeting || {};
  const interests = [...(t.interests || [])];
  for (const spec of (t.flexible_spec || [])) {
    interests.push(...(spec.interests || []));
  }
  for (const interest of interests) {
    if (interest && interest.name) {
      targeting.push({ adset_id: adset.id || '', interest: interest.name });
    }
  }
}

return {
  json: {
    account_id: prev.account_id,
    account_name: prev.account_name,
    google_ads_cred: prev.google_ads_cred,
    meta_ads: {
      campaigns: prev.campaigns,
      ads: prev.ads,
      creatives: prev.creatives,
      breakdowns: prev.breakdowns,
      targeting,
    },
  },
};

const account = $json;
return {
  json: {
    account_id: account.account_id,
    account_name: account.name,
    google_ads_cred: account.google_ads,
    meta_ads: { campaigns: [], ads: [], creatives: {}, breakdowns: [], targeting: [] },
  },
};

// ponytail: Google Ads OAuth (access_token/customer_id/login_customer_id) isn't
// collected anywhere in the connect flow yet (only developer_token is stored),
// so this branch can't run for real. Wire the GAQL searchStream fetch here once
// /accounts/connect collects those fields and this IF can actually go true.
return { json: { ...$json, google_ads: { campaigns: [] } } };

const item = $json;
return {
  json: {
    account_id: item.account_id,
    account_name: item.account_name,
    fetched_at: new Date().toISOString(),
    platforms: {
      meta_ads: item.meta_ads,
      google_ads: item.google_ads,
    },
  },
};
